+TEST("convert fails for rule with non-record entry") {
+  auto yaml_str = R"__(
+rules:
+  - "not a record"
+)__";
+  const auto yaml = unbox(from_yaml(yaml_str));
+  index_config config;
+  auto result = convert(yaml, config);
